window.isSplitterActive = false;
const tools = document.querySelector('.header-tools');
if (tools && !document.getElementById('toggle-splitter')) {
    const btn = document.createElement('div');
    btn.className = 'splitter-btn';
    btn.id = 'toggle-splitter';
    btn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="8" y1="6" x2="21" y2="6"></line><line x1="8" y1="12" x2="21" y2="12"></line><line x1="8" y1="18" x2="21" y2="18"></line><line x1="3" y1="6" x2="3.01" y2="6"></line><line x1="3" y1="12" x2="3.01" y2="12"></line><line x1="3" y1="18" x2="3.01" y2="18"></line></svg>';
    btn.onclick = function() {
        window.isSplitterActive = !window.isSplitterActive;
        this.classList.toggle('active', window.isSplitterActive);
        if (typeof window.refreshTree === 'function') window.refreshTree();
    };
    tools.appendChild(btn);
}
